import{_ as t,c as a,o as i,ag as l}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Email Input Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/email.md","filePath":"fields/email.md","lastUpdated":null}'),o={name:"fields/email.md"};function n(r,e,s,d,h,c){return i(),a("div",null,e[0]||(e[0]=[l('<h1 id="email-input-field" tabindex="-1">Email Input Field <a class="header-anchor" href="#email-input-field" aria-label="Permalink to &quot;Email Input Field&quot;">​</a></h1><p>The <strong>Email Input</strong> field provides a text input that is validated to ensure the customer enters a properly formatted email address. The browser enforces email format on the frontend, and OptionBay performs additional validation on the server side.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Collecting a recipient email for a digital gift card delivery</li><li>Gathering a contact email for a personalized service (e.g., &quot;Where should we send the proof?&quot;)</li><li>Capturing an alternate email for order-related communications</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add an Email field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the input (e.g., &quot;Recipient Email Address&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the input (e.g., &quot;We&#39;ll send the e-gift card to this address&quot;).</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must enter a valid email before adding the product to the cart.</td></tr></tbody></table><h3 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h3><p>Since the Email field is not an options-based field, pricing is configured at the <strong>field level</strong>:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">Choose how the field affects the product price. Available types: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>. In most cases, email fields use &quot;No Price&quot; since they are informational.</td></tr><tr><td style="text-align:left;"><strong>Price Amount</strong></td><td style="text-align:left;">The numeric value to add if a price type other than &quot;No Price&quot; is selected.</td></tr></tbody></table><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Recipient Email&quot; field only when the customer selects &quot;Send as Gift&quot; from a radio button group.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',14)]))}const f=t(o,[["render",n]]);export{u as __pageData,f as default};
